package uk.ac.ed.ltg.jdm.util;import java.io.File;import java.io.IOException;import org.apache.commons.io.FileUtils;import org.apache.log4j.Logger;import uk.ac.ed.ltg.jdm.exception.ReaderException;import uk.ac.ed.ltg.jdm.exception.WriterException;import uk.ac.ed.ltg.jdm.io.FileReader;import uk.ac.ed.ltg.jdm.io.FileReaderFactory;import uk.ac.ed.ltg.jdm.io.FileWriter;import uk.ac.ed.ltg.jdm.io.V3LTGWriter;import uk.ac.ed.ltg.jdm.textdata.Document;/** * This class manages a Cache for storing * {@link uk.ac.ed.ltg.jdm.textdata.Document}s. *  * The constructor takes a File pointing to the folder where the cached * documents will be stored. The class then provides a number of methods to * allow documents to be added to or retrieved from this cache. */public class DocumentCache {	/** The Constant logger. */	private static final Logger LOGGER = Logger.getLogger(DocumentCache.class);	/** The default cache. */	private static DocumentCache defaultCache = null;	/**	 * Construct a cache and create a new {@code DocumentCache} directory in the	 * current working directory to store it in.	 * 	 * @return the document cache	 */	public static DocumentCache defaultCache() {		if (defaultCache == null) {			final File cacheFolder = new File("DocumentCache");			cacheFolder.mkdir();			defaultCache = new DocumentCache(cacheFolder);		}		return defaultCache;	}	/** The cache folder. */	private File cacheFolder = null;	private final FileReader reader = FileReaderFactory.newFileReaderFactory(			FileReaderFactory.Type.SAX).createLTGFileReader();	private final FileWriter writer = new V3LTGWriter();	/**	 * Create a document cache inside the specified file directory (folder).	 * 	 * @param cacheFolder	 *            a File pointing to the directory to be used as a cache.	 */	public DocumentCache(final File cacheFolder) {		this.cacheFolder = cacheFolder;	}	/**	 * Retrieve a document by a unique ID.	 * 	 * @param id	 *            the id	 * 	 * @return the document	 */	public Document retrieveDocument(final String id) {		final File file = new File(this.cacheFolder, id);		if (file.exists()) {			if (LOGGER.isDebugEnabled()) {				LOGGER.debug("Reading document from cache: " + file.getPath());			}			final Document document = new Document();			try {				reader.parse(file, document);			} catch (final ReaderException e) {				e.printStackTrace();			}			return document;		} else			return null;	}	/**	 * Store a document object, given a unique ID to store it under. If the file	 * already exists in the cache then it will be deleted from the cache before	 * the new file is written.	 * 	 * @param id	 *            the id	 * @param document	 *            the document	 */	public void storeDocument(final String id, final Document document) {		final File file = new File(this.cacheFolder, id);		if (file.exists()) {			file.delete();		}		if (LOGGER.isDebugEnabled()) {			LOGGER.debug("Writing document to cache: " + file.getPath());		}		try {			writer.write(document, file);		} catch (final WriterException e) {			e.printStackTrace();		}	}	/**	 * Store a document that currently exists as a file in the fileSystem into	 * the document cache, given a unique ID. If the file already exists in the	 * cache the cache entry will be deleted before the new document is written.	 * 	 * @param id	 *            the unique id	 * @param existingFile	 *            the existing file to be copied into the cache	 * 	 * @throws IOException	 *             Signals that an I/O exception has occurred.	 */	public void storeDocument(final String id, final File existingFile)			throws IOException {		final File file = new File(this.cacheFolder, id);		if (file.exists()) {			file.delete();		}		if (existingFile.exists()) {			if (LOGGER.isDebugEnabled()) {				LOGGER.debug("Copying document to cache: " + file.getPath());			}			FileUtils.copyFile(existingFile, file);		}	}}